// Generates the Python password-hashing demo shown on the Done step.
//
// Two roundtrips (hash + verify-success + verify-fail) — one with Argon2id
// via argon2-cffi, one with bcrypt. The PHC-format hashes both libraries
// emit embed the salt + parameters, so storage is one string per user.

export function full_script(_state) {
  return [
    "# Password hashing in Python — generated by cloak.moosha.org",
    "#",
    "# Two industry-standard libraries, two install commands:",
    "#   pip install argon2-cffi bcrypt",
    "#",
    "# argon2-cffi is the canonical Python binding for the Argon2 reference",
    "# implementation. bcrypt is the canonical Python binding for the OpenBSD",
    "# bcrypt implementation. If you need a single library that exposes many",
    "# password hash algorithms behind one API, look at `passlib` — it wraps",
    "# Argon2, bcrypt, PBKDF2, scrypt, and historical algorithms (MD5-crypt,",
    "# SHA-crypt, etc.) for legacy migrations.",
    "#",
    "# The demo password below is the xkcd-936 'correct horse battery staple'",
    "# — long enough that hashing it the right way matters.",
    "",
    "import argon2",
    "from argon2 import PasswordHasher",
    "import bcrypt",
    "",
    'PASSWORD = "correct-horse-battery-staple"',
    'WRONG    = "Tr0ub4dor&3"',
    "",
    "# --- Argon2id ----------------------------------------------------",
    "# Argon2id is the modern default (PHC 2015 winner, RFC 9106). Memory-hard,",
    "# so an attacker can't trade megabytes of RAM for parallelism on a GPU.",
    "# The PasswordHasher() defaults pick sensible parameters (m=64MB, t=3,",
    "# p=4); tune with `time_cost=`, `memory_cost=`, `parallelism=` if you",
    "# need to match server capacity.",
    "ph = PasswordHasher()",
    "argon2_hash = ph.hash(PASSWORD)",
    'print("argon2id:", argon2_hash)',
    "",
    "# Verify-success: ph.verify raises argon2.exceptions.VerifyMismatchError",
    "# on failure, returns True on success.",
    "assert ph.verify(argon2_hash, PASSWORD) is True",
    'print("\\u2713 argon2id verify OK")',
    "",
    "# Verify-fail: wrong password raises VerifyMismatchError. We catch it",
    "# and assert that's exactly what happened — no silent acceptance.",
    "try:",
    "    ph.verify(argon2_hash, WRONG)",
    '    raise AssertionError("verify should have rejected the wrong password")',
    "except argon2.exceptions.VerifyMismatchError:",
    '    print("\\u2713 argon2id rejected wrong password")',
    "",
    "# --- bcrypt ------------------------------------------------------",
    "# bcrypt is the workhorse of pre-Argon2 password storage. Built on the",
    "# Blowfish key schedule — the cost parameter controls work exponentially",
    "# (cost 12 = 2^12 iterations of the schedule). Rounds=12 is a reasonable",
    "# 2024 default; bump to 13-14 if you can afford the latency.",
    "#",
    "# bcrypt.hashpw embeds the salt + cost in the output, so you store one",
    "# string per user. bcrypt.checkpw recomputes with those embedded params.",
    'pw_bytes = PASSWORD.encode("utf-8")',
    "bcrypt_hash = bcrypt.hashpw(pw_bytes, bcrypt.gensalt(rounds=12))",
    'print("bcrypt  :", bcrypt_hash.decode())',
    "",
    "# Verify-success: bcrypt.checkpw returns True on a match.",
    "assert bcrypt.checkpw(pw_bytes, bcrypt_hash) is True",
    'print("\\u2713 bcrypt verify OK")',
    "",
    "# Verify-fail: wrong password -> False, no exception.",
    'assert bcrypt.checkpw(WRONG.encode("utf-8"), bcrypt_hash) is False',
    'print("\\u2713 bcrypt rejected wrong password")',
    "",
    "# That's the full picture: derive a slow, salted hash once at signup,",
    "# store it, and re-derive at login to compare. Argon2id is the default",
    "# for new systems; bcrypt is fine for existing deployments at cost 12+;",
    "# PBKDF2-HMAC-SHA256 at >=600k iterations is the FIPS-compliant fallback.",
    "# Never plain SHA-256. Never plaintext. Never your own scheme.",
  ].join("\n");
}

